-- Generated from เบอร์รายเดือนล่าสุด 31-3-69.xlsx
-- Scope: sync postpaid phone_numbers status + price to the latest Excel snapshot.
-- Safe behavior: numbers absent from Excel are changed to olded only when current status is active/hold/olded/null; sold is preserved unless the number reappears in Excel.
-- Usage: select the target production database first, then run this script.

SET @OLD_SQL_SAFE_UPDATES := @@SQL_SAFE_UPDATES;
SET SQL_SAFE_UPDATES = 0;

START TRANSACTION;

DROP TEMPORARY TABLE IF EXISTS latest_postpaid_20260331;
CREATE TEMPORARY TABLE latest_postpaid_20260331 (
    phone_number VARCHAR(10) NOT NULL PRIMARY KEY,
    excel_price INT NOT NULL
) ENGINE=InnoDB;






























UPDATE phone_numbers p
JOIN latest_postpaid_20260331 l ON l.phone_number = p.phone_number
SET p.status = 'active'
WHERE p.service_type = 'postpaid'
  AND COALESCE(p.status, '') <> 'active';
SELECT 'activated_rows' AS metric, ROW_COUNT() AS value;

UPDATE phone_numbers p
LEFT JOIN latest_postpaid_20260331 l ON l.phone_number = p.phone_number
SET p.status = 'olded'
WHERE p.service_type = 'postpaid'
  AND l.phone_number IS NULL
  AND (p.status IN ('active', 'hold', 'olded') OR p.status IS NULL);
SELECT 'olded_rows' AS metric, ROW_COUNT() AS value;

UPDATE phone_numbers p
JOIN latest_postpaid_20260331 l ON l.phone_number = p.phone_number
SET p.sale_price = l.excel_price,
    p.price_text = CAST(l.excel_price AS CHAR)
WHERE p.service_type = 'postpaid'
  AND NOT (p.sale_price <=> l.excel_price);
SELECT 'price_updated_rows' AS metric, ROW_COUNT() AS value;

UPDATE phone_numbers
SET sale_price = 1199,
    price_text = '1199'
WHERE service_type = 'postpaid'
  AND (sale_price = 1099 OR TRIM(COALESCE(price_text, '')) = '1099');
SELECT 'normalized_1099_to_1199_rows' AS metric, ROW_COUNT() AS value;

COMMIT;

SET SQL_SAFE_UPDATES = @OLD_SQL_SAFE_UPDATES;

SELECT 'postpaid_status' AS metric, status AS label, COUNT(*) AS value
FROM phone_numbers
WHERE service_type = 'postpaid'
GROUP BY status
ORDER BY value DESC;

SELECT 'postpaid_price' AS metric, COALESCE(CAST(sale_price AS CHAR), 'NULL') AS label, COUNT(*) AS value
FROM phone_numbers
WHERE service_type = 'postpaid'
GROUP BY sale_price
ORDER BY sale_price;

SELECT 'matched_price_mismatch_after' AS metric, COUNT(*) AS value
FROM latest_postpaid_20260331 l
JOIN phone_numbers p ON p.phone_number = l.phone_number
WHERE p.service_type = 'postpaid'
  AND NOT (p.sale_price <=> l.excel_price);
